// Format number nicely
function fmt(n) {
  if (n === Math.floor(n)) return n.toString();
  return parseFloat(n.toFixed(1)).toString();
}

// Difficulty badge colors
const diffColors = {
  "קל": { bg: "#E8F5E9", text: "#2E7D32" },
  "בינוני": { bg: "#FFF3E0", text: "#E65100" },
  "קשה": { bg: "#FCE4EC", text: "#C62828" },
};

function RecipeCard({ recipe, onClick }) {
  return (
    <div
      onClick={() => onClick(recipe)}
      style={{
        background: "#fff",
        borderRadius: 20,
        overflow: "hidden",
        cursor: "pointer",
        boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
        transition: "transform 0.2s, box-shadow 0.2s",
        border: "1px solid #F0EDE8",
      }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = "translateY(-4px)";
        e.currentTarget.style.boxShadow = "0 8px 28px rgba(0,0,0,0.13)";
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.08)";
      }}
    >
      <div style={{ position: "relative", height: 180, overflow: "hidden" }}>
        <img
          src={recipe.image}
          alt={recipe.title}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
        />
        <div style={{
          position: "absolute", bottom: 10, right: 12,
          background: "#fff",
          borderRadius: 20,
          padding: "3px 10px",
          fontSize: 12,
          fontWeight: 600,
          color: diffColors[recipe.difficulty]?.text || "#333",
          backgroundColor: diffColors[recipe.difficulty]?.bg || "#eee",
        }}>
          {recipe.difficulty}
        </div>
      </div>
      <div style={{ padding: "14px 16px 16px" }}>
        <h3 style={{ margin: 0, fontSize: 16, fontWeight: 700, color: "#1A1A1A", fontFamily: "'Playfair Display', serif" }}>
          {recipe.title}
        </h3>
        <div style={{ display: "flex", gap: 12, marginTop: 8, color: "#888", fontSize: 13 }}>
          <span>⏱ {recipe.prepTime}</span>
          <span>👥 {recipe.baseServings} מנות</span>
        </div>
      </div>
    </div>
  );
}

function RecipeModal({ recipe, onClose }) {
  const [servings, setServings] = useState(recipe.baseServings);
  const ratio = servings / recipe.baseServings;

  useEffect(() => {
    setServings(recipe.baseServings);
  }, [recipe]);

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)",
      zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center",
      padding: 16,
      backdropFilter: "blur(4px)",
    }}
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div style={{
        background: "#fff",
        borderRadius: 24,
        width: "100%",
        maxWidth: 560,
        maxHeight: "90vh",
        overflowY: "auto",
        boxShadow: "0 24px 80px rgba(0,0,0,0.2)",
        direction: "rtl",
      }}>
        {/* Image */}
        <div style={{ position: "relative", height: 260, overflow: "hidden", borderRadius: "24px 24px 0 0" }}>
          <img src={recipe.image} alt={recipe.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          <button
            onClick={onClose}
            style={{
              position: "absolute", top: 14, left: 14,
              background: "rgba(255,255,255,0.92)",
              border: "none", borderRadius: "50%",
              width: 38, height: 38, cursor: "pointer",
              fontSize: 18, display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: "0 2px 8px rgba(0,0,0,0.12)",
            }}
          >✕</button>
          <div style={{
            position: "absolute", bottom: 0, left: 0, right: 0,
            background: "linear-gradient(transparent, rgba(0,0,0,0.6))",
            padding: "30px 20px 18px",
          }}>
            <h2 style={{ margin: 0, color: "#fff", fontSize: 24, fontFamily: "'Playfair Display', serif" }}>
              {recipe.title}
            </h2>
            <div style={{ color: "rgba(255,255,255,0.85)", fontSize: 13, marginTop: 4 }}>
              ⏱ {recipe.prepTime} &nbsp;·&nbsp; 👥 {recipe.baseServings} מנות בסיס
            </div>
          </div>
        </div>

        <div style={{ padding: "22px 24px 28px" }}>
          {/* Serving adjuster */}
          <div style={{
            background: "#F8F6F3",
            borderRadius: 16,
            padding: "14px 18px",
            marginBottom: 22,
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}>
            <span style={{ fontWeight: 700, fontSize: 15, color: "#1A1A1A" }}>מספר מנות</span>
            <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
              <button
                onClick={() => setServings(s => Math.max(1, s - 1))}
                style={{
                  width: 34, height: 34, borderRadius: "50%",
                  background: servings <= 1 ? "#eee" : "#C9A84C",
                  color: servings <= 1 ? "#aaa" : "#fff",
                  border: "none", cursor: servings <= 1 ? "default" : "pointer",
                  fontSize: 20, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center",
                }}
              >−</button>
              <span style={{ fontSize: 22, fontWeight: 700, minWidth: 28, textAlign: "center", color: "#1A1A1A" }}>
                {servings}
              </span>
              <button
                onClick={() => setServings(s => s + 1)}
                style={{
                  width: 34, height: 34, borderRadius: "50%",
                  background: "#C9A84C",
                  color: "#fff",
                  border: "none", cursor: "pointer",
                  fontSize: 20, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center",
                }}
              >+</button>
            </div>
          </div>

          {/* Ingredients */}
          <h3 style={{ fontSize: 17, fontWeight: 700, color: "#1A1A1A", marginBottom: 12, marginTop: 0 }}>
            🧂 מצרכים
          </h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 24 }}>
            {recipe.ingredients.map((ing, i) => (
              <div key={i} style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                padding: "8px 14px",
                background: i % 2 === 0 ? "#F8F6F3" : "#fff",
                borderRadius: 10,
                border: "1px solid #F0EDE8",
              }}>
                <span style={{ color: "#333", fontSize: 14 }}>{ing.name}</span>
                <span style={{
                  fontWeight: 700, color: "#C9A84C", fontSize: 14,
                  background: "#FFF8EC",
                  padding: "2px 10px",
                  borderRadius: 20,
                }}>
                  {fmt(ing.amount * ratio)} {ing.unit}
                </span>
              </div>
            ))}
          </div>

          {/* Steps */}
          <h3 style={{ fontSize: 17, fontWeight: 700, color: "#1A1A1A", marginBottom: 12, marginTop: 0 }}>
            👨‍🍳 אופן הכנה
          </h3>
          <ol style={{ paddingRight: 20, margin: 0, display: "flex", flexDirection: "column", gap: 12 }}>
            {recipe.steps.map((step, i) => (
              <li key={i} style={{ color: "#444", fontSize: 14, lineHeight: 1.7 }}>
                {step}
              </li>
            ))}
          </ol>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [activeCategory, setActiveCategory] = useState("all");
  const [search, setSearch] = useState("");
  const [selectedRecipe, setSelectedRecipe] = useState(null);
  const [recipes] = useState(SAMPLE_RECIPES);

  const filtered = recipes.filter(r => {
    const matchCat = activeCategory === "all" || r.category === activeCategory;
    const matchSearch = r.title.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  return (
    <div style={{
      minHeight: "100vh",
      background: "#FAFAF8",
      fontFamily: "'Inter', 'Segoe UI', sans-serif",
      direction: "rtl",
    }}>
      {/* Header */}
      <div style={{
        background: "#1A1A1A",
        padding: "0 20px",
        position: "sticky",
        top: 0,
        zIndex: 100,
      }}>
        <div style={{ maxWidth: 720, margin: "0 auto" }}>
          <div style={{ paddingTop: 18, paddingBottom: 6 }}>
            <div>
              <div style={{ color: "#C9A84C", fontSize: 11, fontWeight: 600, letterSpacing: 3, textTransform: "uppercase" }}>
                ✦ MY KITCHEN
              </div>
              <h1 style={{
                color: "#fff",
                margin: "2px 0 0",
                fontSize: 22,
                fontFamily: "'Playfair Display', serif",
                fontWeight: 700,
              }}>
                ספר המתכונים שלי
              </h1>
            </div>
          </div>

          {/* Search */}
          <div style={{ position: "relative", marginBottom: 14 }}>
            <span style={{ position: "absolute", right: 14, top: "50%", transform: "translateY(-50%)", color: "#888", fontSize: 16, pointerEvents: "none" }}>🔍</span>
            <input
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="חפש מתכון..."
              style={{
                width: "100%",
                padding: "11px 42px 11px 14px",
                borderRadius: 14,
                border: "none",
                background: "rgba(255,255,255,0.1)",
                color: "#fff",
                fontSize: 14,
                outline: "none",
                boxSizing: "border-box",
              }}
            />
          </div>

          {/* Category tabs */}
          <div style={{ display: "flex", gap: 6, paddingBottom: 14, overflowX: "auto" }}>
            {CATEGORIES.map(cat => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                style={{
                  whiteSpace: "nowrap",
                  padding: "7px 16px",
                  borderRadius: 20,
                  border: "none",
                  background: activeCategory === cat.id ? "#C9A84C" : "rgba(255,255,255,0.1)",
                  color: activeCategory === cat.id ? "#fff" : "rgba(255,255,255,0.7)",
                  fontWeight: 600,
                  fontSize: 13,
                  cursor: "pointer",
                  transition: "all 0.2s",
                }}
              >
                {cat.icon} {cat.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main */}
      <div style={{ maxWidth: 720, margin: "0 auto", padding: "22px 16px 40px" }}>
        {/* Count */}
        <div style={{ fontSize: 13, color: "#999", marginBottom: 16, fontWeight: 500 }}>
          {filtered.length} מתכונים
          {search && <span> עבור "<strong style={{ color: "#C9A84C" }}>{search}</strong>"</span>}
        </div>

        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 20px", color: "#aaa" }}>
            <div style={{ fontSize: 52, marginBottom: 12 }}>🍽️</div>
            <p style={{ fontWeight: 600, color: "#555", fontSize: 16 }}>לא נמצאו מתכונים</p>
            <p style={{ fontSize: 14 }}>נסה לשנות את החיפוש או הוסף מתכון חדש</p>
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))",
            gap: 18,
          }}>
            {filtered.map(recipe => (
              <RecipeCard key={recipe.id} recipe={recipe} onClick={setSelectedRecipe} />
            ))}
          </div>
        )}
      </div>

      {/* Modals */}
      {selectedRecipe && (
        <RecipeModal recipe={selectedRecipe} onClose={() => setSelectedRecipe(null)} />
      )}
    </div>
  );
}
